import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine().trim();

        // Limit the buffer size to avoid buffer overflow
        int bufferSize = Math.min(input.length(), 10);

        // Copy the user input into a properly sized buffer
        char[] buffer = new char[bufferSize];

        // Copy only up to the size of the buffer
        input.getChars(0, bufferSize, buffer, 0);

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

